class Solution:
    def countOperations(self, num1: int, num2: int) -> int:
        a, b = num1, num2
        count = 0
        while a != 0 and b != 0:
            if a == b:
                count += 1
                break
            elif a > b:
                count += a // b
                a = a % b
            else:
                count += b // a
                b = b % a
        return count

